120	  public SslContext sslContext(String serverName, boolean useAlpn, boolean server) throws Exception {
121	    int idx = idx(useAlpn);
122	    if (serverName != null) {
123	      KeyManagerFactory kmf = resolveKeyManagerFactory(serverName);
124	      TrustManager[] trustManagers = resolveTrustManagers(serverName);
125	      if (kmf != null || trustManagers != null || !server) {
126	        return sslContextMaps[idx].computeIfAbsent(serverName, s -> createContext(server, kmf, trustManagers, s, useAlpn));
127	      }
128	    }
129	    if (sslContexts[idx] == null) {
130	      SslContext context = createContext(server, null, null, serverName, useAlpn);
131	      sslContexts[idx] = context;
132	    }
133	    return sslContexts[idx];
134	  }
