149	  public AsyncMapping<? super String, ? extends SslContext> serverNameMapping(Executor workerPool, boolean useAlpn) {
150	    return (AsyncMapping<String, SslContext>) (serverName, promise) -> {
151	      workerPool.execute(() -> {
152	        SslContext sslContext;
153	        try {
154	          sslContext = sslContext(serverName, useAlpn, true);
155	        } catch (Exception e) {
156	          promise.setFailure(e);
157	          return;
158	        }
159	        promise.setSuccess(sslContext);
160	      });
161	      return promise;
162	    };
163	  }
