 60	  /**
 61	   * Resolve the ssl engine options to use for properly running the configured options.
 62	   */
 63	  public static SSLEngineOptions resolveEngineOptions(SSLEngineOptions engineOptions, boolean useAlpn) {
 64	    if (engineOptions == null) {
 65	      if (useAlpn) {
 66	        if (JdkSSLEngineOptions.isAlpnAvailable()) {
 67	          engineOptions = new JdkSSLEngineOptions();
 68	        } else if (OpenSSLEngineOptions.isAlpnAvailable()) {
 69	          engineOptions = new OpenSSLEngineOptions();
 70	        }
 71	      }
 72	    }
 73	    if (engineOptions == null) {
 74	      engineOptions = new JdkSSLEngineOptions();
 75	    } else if (engineOptions instanceof OpenSSLEngineOptions) {
 76	      if (!OpenSsl.isAvailable()) {
 77	        VertxException ex = new VertxException("OpenSSL is not available");
 78	        Throwable cause = OpenSsl.unavailabilityCause();
 79	        if (cause != null) {
 80	          ex.initCause(cause);
 81	        }
 82	        throw ex;
 83	      }
 84	    }
 85	
 86	    if (useAlpn) {
 87	      if (engineOptions instanceof JdkSSLEngineOptions) {
 88	        if (!JdkSSLEngineOptions.isAlpnAvailable()) {
 89	          throw new VertxException("ALPN not available for JDK SSL/TLS engine");
 90	        }
 91	      }
 92	      if (engineOptions instanceof OpenSSLEngineOptions) {
 93	        if (!OpenSSLEngineOptions.isAlpnAvailable()) {
 94	          throw new VertxException("ALPN is not available for OpenSSL SSL/TLS engine");
 95	        }
 96	      }
 97	    }
 98	    return engineOptions;
 99	  }
