120	  public Future<SslContextProvider> resolveSslContextProvider(SSLOptions options, String hostnameVerificationAlgorithm, ClientAuth clientAuth, List<String> applicationProtocols, boolean force, ContextInternal ctx) {
121	    Promise<SslContextProvider> promise;
122	    ConfigKey k = new ConfigKey(options);
123	    synchronized (this) {
124	      if (force) {
125	        sslContextProviderMap.remove(k);
126	      } else {
127	        Future<SslContextProvider> v = sslContextProviderMap.get(k);
128	        if (v != null) {
129	          return v;
130	        }
131	      }
132	      promise = Promise.promise();
133	      sslContextProviderMap.put(k, promise.future());
134	    }
135	    buildSslContextProvider(options, hostnameVerificationAlgorithm, clientAuth, applicationProtocols, force, ctx)
136	      .onComplete(promise);
137	    return promise.future();
