156	  private SslContextProvider buildSslContextProvider(SSLOptions sslOptions, String hostnameVerificationAlgorithm, Supplier<SslContextFactory> supplier, ClientAuth clientAuth, List<String> applicationProtocols, Config config) {
157	    if (clientAuth == null && hostnameVerificationAlgorithm == null) {
158	      throw new VertxException("Missing hostname verification algorithm: you must set TCP client options host name" +
159	        " verification algorithm");
160	    }
161	    return new SslContextProvider(
162	      useWorkerPool,
163	      clientAuth,
164	      hostnameVerificationAlgorithm,
165	      applicationProtocols,
166	      sslOptions.getEnabledCipherSuites(),
167	      sslOptions.getEnabledSecureTransportProtocols(),
168	      config.keyManagerFactory,
169	      config.keyManagerFactoryMapper,
170	      config.trustManagerFactory,
171	      config.trustManagerMapper,
172	      config.crls,
173	      supplier);
174	  }
