176	  private static TrustOptions trustOptionsOf(SSLOptions sslOptions) {
177	    if (sslOptions instanceof ClientSSLOptions) {
178	      ClientSSLOptions clientSSLOptions = (ClientSSLOptions) sslOptions;
179	      if (clientSSLOptions.isTrustAll()) {
180	        return TrustAllOptions.INSTANCE;
181	      }
182	    }
183	    return sslOptions.getTrustOptions();
184	  }
185	
186	  private Future<Config> buildConfig(SSLOptions sslOptions, boolean force, ContextInternal ctx) {
187	    if (trustOptionsOf(sslOptions) == null && sslOptions.getKeyCertOptions() == null) {
188	      return ctx.succeededFuture(NULL_CONFIG);
189	    }
190	    Promise<Config> promise;
191	    ConfigKey k = new ConfigKey(sslOptions);
192	    synchronized (this) {
193	      if (force) {
194	        configMap.remove(k);
195	      } else {
196	        Future<Config> fut = configMap.get(k);
197	        if (fut != null) {
198	          return fut;
199	        }
200	      }
201	      promise = Promise.promise();
202	      configMap.put(k, promise.future());
203	    }
204	    ctx.executeBlockingInternal(() -> {
205	      KeyManagerFactory keyManagerFactory = null;
206	      Function<String, KeyManagerFactory> keyManagerFactoryMapper = null;
207	      TrustManagerFactory trustManagerFactory = null;
208	      Function<String, TrustManager[]> trustManagerMapper = null;
209	      List<CRL> crls = new ArrayList<>();
210	      if (sslOptions.getKeyCertOptions() != null) {
211	        keyManagerFactory = sslOptions.getKeyCertOptions().getKeyManagerFactory(ctx.owner());
212	        keyManagerFactoryMapper = sslOptions.getKeyCertOptions().keyManagerFactoryMapper(ctx.owner());
213	      }
214	      TrustOptions trustOptions = trustOptionsOf(sslOptions);
215	      if (trustOptions != null) {
216	        trustManagerFactory = trustOptions.getTrustManagerFactory(ctx.owner());
217	        trustManagerMapper = trustOptions.trustManagerMapper(ctx.owner());
218	      }
219	      List<Buffer> tmp = new ArrayList<>();
220	      if (sslOptions.getCrlPaths() != null) {
221	        tmp.addAll(sslOptions.getCrlPaths()
222	          .stream()
223	          .map(path -> ctx.owner().fileResolver().resolve(path).getAbsolutePath())
224	          .map(ctx.owner().fileSystem()::readFileBlocking)
225	          .collect(Collectors.toList()));
226	      }
227	      if (sslOptions.getCrlValues() != null) {
228	        tmp.addAll(sslOptions.getCrlValues());
229	      }
230	      CertificateFactory certificatefactory = CertificateFactory.getInstance("X.509");
231	      for (Buffer crlValue : tmp) {
232	        crls.addAll(certificatefactory.generateCRLs(new ByteArrayInputStream(crlValue.getBytes())));
233	      }
234	      return new Config(keyManagerFactory, trustManagerFactory, keyManagerFactoryMapper, trustManagerMapper, crls);
235	    }).onComplete(promise);
236	    return promise.future();
237	  }
