323	  public void configureEngine(SSLEngine engine, Set<String> enabledProtocols, String serverName, boolean client) {
324	    Set<String> protocols = new LinkedHashSet<>(enabledProtocols);
325	    protocols.retainAll(Arrays.asList(engine.getSupportedProtocols()));
326	    engine.setEnabledProtocols(protocols.toArray(new String[protocols.size()]));
327	    if (client) {
