366	  public Future<Boolean> updateTrafficShapingOptions(TrafficShapingOptions options) {
367	    if (options == null) {
368	      throw new IllegalArgumentException("Invalid null value passed for traffic shaping options update");
369	    }
370	    NetServerImpl server = actualServer;
371	    ContextInternal ctx = vertx.getOrCreateContext();
372	    if (server == null) {
373	      // Server not yet started
374	      TrafficShapingOptions prev = this.options.getTrafficShapingOptions();
375	      boolean updated = prev == null || !prev.equals(options);
376	      this.options.setTrafficShapingOptions(options);
377	      return ctx.succeededFuture(updated);
378	    }
379	    // Update the traffic shaping options only for the actual/main server
380	    if (server != this) {
381	      return server.updateTrafficShapingOptions(options);
382	    } else {
383	      Promise<Boolean> promise = ctx.promise();
384	      ctx.emit(v -> updateTrafficShapingOptions(options, promise));
385	      return promise.future();
