392	        "to use traffic shaping during startup"));
393	    } else if (!options.equals(this.options.getTrafficShapingOptions())) {
394	      // Compare with existing traffic-shaping options to ensure they are updated only when they differ.
395	      this.options.setTrafficShapingOptions(options);
396	      long checkIntervalForStatsInMillis = options.getCheckIntervalForStatsTimeUnit().toMillis(options.getCheckIntervalForStats());
397	      trafficShapingHandler.configure(options.getOutboundGlobalBandwidth(), options.getInboundGlobalBandwidth(), checkIntervalForStatsInMillis);
398	      if (options.getPeakOutboundGlobalBandwidth() != 0) {
